mapper.select:
SELECT student.id, student.name, student.no, student.gender, student.phone, student.id_card AS idCard, student.is_college AS isCollege, student.address, student.dept_id AS deptId, student.graduation_date AS graduationDate, student.violation_count AS violationCount, student.violation_score AS violationScore, student.clazz_id AS clazzId, clazz.name AS clazzName, student.create_time AS createTime, student.update_time AS updateTime FROM student LEFT JOIN clazz ON student.clazz_id = clazz.id
AND student.name like concat('%',#{name},'%')
AND student.clazz_id = #{clazzId}
AND student.dept_id = #{deptId}
ORDER BY student.update_time DESC
